def _parse(pattern):
    pos = 0
    n = len(pattern)

    def parse_alt():
        nonlocal pos
        branches = [parse_cat()]
        while pos < n and pattern[pos] == '|':
            pos += 1
            branches.append(parse_cat())
        if len(branches) == 1:
            return branches[0]
        return ('alt', branches)

    def parse_cat():
        items = []
        while pos < n and pattern[pos] not in '|)':
            items.append(parse_repeat())
        return ('cat', items)

    def parse_repeat():
        nonlocal pos
        node = parse_atom()
        while pos < n and pattern[pos] in '*+?':
            q = pattern[pos]
            pos += 1
            if q == '*':
                node = ('star', node)
            elif q == '+':
                node = ('plus', node)
            else:
                node = ('opt', node)
        return node

    def parse_atom():
        nonlocal pos
        c = pattern[pos]
        if c == '(':
            pos += 1
            node = parse_alt()
            pos += 1  # ')'
            return node
        if c == '[':
            pos += 1
            negated = False
            if pos < n and pattern[pos] == '^':
                negated = True
                pos += 1
            items = []
            first = True
            while pos < n and (pattern[pos] != ']' or first):
                lo = pattern[pos]
                pos += 1
                if pos + 1 < n and pattern[pos] == '-' and pattern[pos + 1] != ']':
                    hi = pattern[pos + 1]
                    pos += 2
                else:
                    hi = lo
                items.append((lo, hi))
                first = False
            pos += 1  # ']'
            return ('class', negated, items)
        if c == '.':
            pos += 1
            return ('any',)
        pos += 1
        return ('lit', c)

    return parse_alt()


def _compile(node):
    # Thompson construction: edges[s] is a list of (label, target);
    # label is None for epsilon, otherwise a ('lit',...)/('any',)/('class',...) node.
    edges = []

    def new_state():
        edges.append([])
        return len(edges) - 1

    def build(node):
        kind = node[0]
        if kind in ('lit', 'any', 'class'):
            s = new_state()
            a = new_state()
            edges[s].append((node, a))
            return s, a
        if kind == 'cat':
            s = new_state()
            cur = s
            for child in node[1]:
                cs, ca = build(child)
                edges[cur].append((None, cs))
                cur = ca
            return s, cur
        if kind == 'alt':
            s = new_state()
            a = new_state()
            for child in node[1]:
                cs, ca = build(child)
                edges[s].append((None, cs))
                edges[ca].append((None, a))
            return s, a
        if kind == 'star':
            s = new_state()
            a = new_state()
            cs, ca = build(node[1])
            edges[s].append((None, cs))
            edges[s].append((None, a))
            edges[ca].append((None, cs))
            edges[ca].append((None, a))
            return s, a
        if kind == 'plus':
            cs, ca = build(node[1])
            a = new_state()
            edges[ca].append((None, cs))
            edges[ca].append((None, a))
            return cs, a
        # 'opt'
        s = new_state()
        a = new_state()
        cs, ca = build(node[1])
        edges[s].append((None, cs))
        edges[s].append((None, a))
        edges[ca].append((None, a))
        return s, a

    start, accept = build(node)
    return start, accept, edges


def _label_matches(label, ch):
    kind = label[0]
    if kind == 'lit':
        return ch == label[1]
    if kind == 'any':
        return True
    negated, items = label[1], label[2]
    hit = False
    for lo, hi in items:
        if lo <= ch <= hi:
            hit = True
            break
    return hit != negated


def match(pattern, text):
    start, accept, edges = _compile(_parse(pattern))

    def closure(states):
        seen = set(states)
        stack = list(states)
        while stack:
            s = stack.pop()
            for label, t in edges[s]:
                if label is None and t not in seen:
                    seen.add(t)
                    stack.append(t)
        return seen

    current = closure({start})
    for ch in text:
        nxt = set()
        for s in current:
            for label, t in edges[s]:
                if label is not None and _label_matches(label, ch):
                    nxt.add(t)
        if not nxt:
            return False
        current = closure(nxt)
    return accept in current
